INSERT INTO public.photos VALUES (22464, 'R├¡o Ebro 1968', 'Foto: Monge. En agosto de 1968, Manuel Miranda surcaba el r├¡o Ebro desde el Club Helios, en un velero. Al fondo, el puente de Santiago y el Pilar. Fuente: Heraldo de Arag├│n.', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST├ôRICO', 41.65878300, -0.88333000, '0101000020E6100000F86BB2463D44ECBF9414580053D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32701185541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32701185541.webp', 'https://www.flickr.com/photos/zaragozaantigua/32701185541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
