INSERT INTO public.photos VALUES (24353, 'Casa Amparo 1930', 'Ayuntamiento de Zaragoza/Mar├¡n Chivite. 1930. "Casa Amparo. Fachada." En 1871, en la calle de Predicadores el Ayuntamiento de Zaragoza cre├│ la Casa Amparo, que en principio albergaba a hu├®rfanos y ancianos, siendo m├ís tarde atendidos solamente estos ├║ltimos.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST├ôRICO', 41.65781900, -0.88796600, '0101000020E6100000CCB73EAC376AECBFFED7B96933D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14914218121.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14914218121.webp', 'https://www.flickr.com/photos/zaragozaantigua/14914218121/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
