INSERT INTO public.photos VALUES (23171, 'Paseo Echegaray 2009', 'Foto: Maite Santonja. Aspecto en agosto de 2009 de las obras de construcci├│n de la Escuela Infantil Municipal El Bosque, en el paseo de Echegaray y Caballero 5, junto al parque de San Pablo (construido dos veces, en 2002 y en 2008). Ser├í inaugurada en 2010. Al fondo, obelisco de la plaza de Europa. Fuente visual: Heraldo de Arag├│n.', 2009, 2009, 2009, 'Siglo XXI', 'CASCO HIST├ôRICO', 41.65942700, -0.89069900, '0101000020E6100000938E72309B80ECBFB98C9B1A68D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33135551406.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33135551406.webp', 'https://www.flickr.com/photos/zaragozaantigua/33135551406/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
