INSERT INTO public.photos VALUES (21971, 'Cine Dorado 1949', 'Entrada del cine Dorado, en el paseo de la Independencia n┬║ 14. Fue inaugurado como cine Dor├® el 10 de octubre de 1914 y cerr├│ en agosto de 1980. El aspecto que presenta en la foto es fruto de su reforma de 1949; fue vuelto a remozar, ya por ├║ltima vez, en 1967. Fuente visual de la imagen: Foto Gerardo Sancho Ramo, en AMZ', 1949, 1949, 1949, 'Anos 40', 'CENTRO', 41.65077200, -0.88269400, '0101000020E61000007903CC7C073FECBF8693347F4CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23640573691.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23640573691.webp', 'https://www.flickr.com/photos/zaragozaantigua/23640573691/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
