INSERT INTO public.photos VALUES (25513, 'Puerta del Carmen c.1920', 'Puerta del Carmen vista desde el paseo de Mar├¡a Agust├¡n. Al fondo, interior de la antigua ciudad. Fuente: Foto Jes├║s Corm├ín. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CENTRO', 41.64982500, -0.88759100, '0101000020E61000007C2AA73D2567ECBFC58F31772DD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24786904732.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24786904732.webp', 'https://www.flickr.com/photos/zaragozaantigua/24786904732/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21040, 'Pl. de la Constituci├│n 1860', '"Zaragoza. Fountain of Isabel II and the Salon of Saint Engracia". Imagen capturada a cierta altura desde la fachada edilicia del Coso recayente a la plaza de la Constituci├│n y el Sal├│n de Santa Engracia, engalanados con ocasi├│n de la visita de la reina Isabel II a la ciudad en octubre de ese a├▒o. En primer t├®rmino, la fuente de la Princesa o de Neptuno fluye en├®rgicamente y abastece de agua a los carros de aguadores estacionados junto a ella. Pareciera que Neptuno, en este caso, hubiera sido despojado de su poderoso tridente, tal vez por reparaci├│n, o hurto. Tanto la fuente como la plaza aparecen delimitadas por firmes y espaciados mojones de piedra. En el arranque del Sal├│n de Santa Engracia, a la derecha, unos de los pr├¡stinos, esbeltos y funcionales mingitorios para aliviar insoslayables necesidades fisiol├│gicas. La variedad de motivos y formas decorativas montados para la ocasi├│n incluyen el monumental trampantojo o picaresca simulaci├│n que al fondo aparentaba, mediante la colocaci├│n de lienzos pintados encima, que la puerta de Santa Engracia era un arco triunfal. El efecto buscado se cumpli├│ al menos durante los d├¡as de visita Real, cuando Isabel II pas├│ bajo ├®l para dar una vuelta por la playa de Torrero y el Canal Imperial, y cuando se dirigi├│ a la explanada de Campo Sepulcro a presidir un desfile militar. A la izquierda del Sal├│n destaca la nov├¡sima fachada del convento de Jerusal├®n, reci├®n reconstruido seg├║n proyecto del arquitecto Pedro Mart├¡nez Sangr├│s. A la derecha, luminosa vista parcial de los porches del Sal├│n, cuando pretend├¡a, y consegu├¡a, ser un reflejo local de la parisina rue de Rivoli. Algunas figuras estacionadas en la plaza adquieren un inquietante perfil borroso, fantasmag├│rico, como consecuencia del dilatado tiempo de exposici├│n empleado por el fot├│grafo para capturar la escena en condiciones ├│ptimas. Fuente visual: Charles Clifford, en J. Paul Getty Museum', 1860, 1860, 1860, 'Siglo XIX', 'CENTRO', 41.65223700, -0.88088000, '0101000020E6100000556AF6402B30ECBFDE1E84807CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44636515855.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44636515855.webp', 'https://www.flickr.com/photos/zaragozaantigua/44636515855/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
