INSERT INTO public.photos VALUES (25340, 'Pl. de la Constituci├│n 1901', 'Coche f├║nebre del enterramiento de "un general espa├▒ol", a su paso por la plaza de la Constituci├│n. A la izquierda, emboque con la calle de los M├írtires. Fuente: www.delcampe.net', 1901, 1901, 1901, 'Anos 1900', 'CENTRO', 41.65230300, -0.88057000, '0101000020E6100000CBD6FA22A12DECBF960A2AAA7ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28512222155.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28512222155.webp', 'https://www.flickr.com/photos/zaragozaantigua/28512222155/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
