INSERT INTO public.photos VALUES (21362, 'Huerva al aire 1918', 'AHPZ-MF-COYNE. 1918. El r├¡o Huerva hab├¡a sido la gran trinchera sure├▒a durante el bienio b├®lico 1808-1809. La fuerte orograf├¡a de su cauce lo hac├¡an natural foso, infranqueable. Por eso la lucha por los puentes, como el de San Jos├®, fue m├ís que encarnizada, hom├®rica. Durante la segunda mitad del XIX la ciudad empez├│ a salir de su medieval cors├® urbano, y se top├│ con el r├¡o. Hubo un proyecto de desviar su curso, pero el presupuesto superaba lo imaginable, y se descart├│ por delirante. Los due├▒os de los terrenos sure├▒os, adem├ís, congelaron cualquier intento de establecer una cabeza de puente hacia el sur, para dar tiempo a que el valor de sus propiedades se multiplicara. S├│lo hubo un controlado escape al bloqueo: el Paseo de Sagasta. Mientras, en las orillas del r├¡o, especialmente a lo largo del Camino del S├íbado, se ubicaron toda suerte de f├íbricas e instalaciones textiles, de curtidos, zapatos, tintes.. que desaguaban residuos y vertidos directamente. A pesar de eso, el r├¡o tambi├®n era un h├íbitat natural para la expansi├│n y recreo, incluyendo el ba├▒o en localizadas "pozas", y la pesca (barbos y cangrejos). La imagen captura el cauce nevado del Huerva antes de su cubrimiento en el arranque de la "Gran V├¡a" (1925-1932). La he volteado horizontalmente porque en su estado original (Archivo Coyne), la Antigua Facultad de Medicina y Ciencias de la Universidad de Zaragoza quedaba en la orilla derecha, y el paisaje ha cambiado mucho desde entonces, pero no hasta ese extremo. Hace unos pocos a├▒os (2009), con motivo de la renovaci├│n de infraestructuras durante la recuperaci├│n del tranv├¡a, el cauce del Huerva volvi├│ a ver la luz natural, 84 a├▒os despu├®s de ser cubierto, y provoc├│ una conmoci├│n ciudadana. Ya pas├│.', 1918, 1918, 1918, 'Anos 10', 'CENTRO', 41.64694100, -0.88583100, '0101000020E6100000240ED940BA58ECBF84B872F6CED24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14665995347.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14665995347.webp', 'https://www.flickr.com/photos/zaragozaantigua/14665995347/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (23069, 'Plaza de Arag├│n 2007', 'Foto Wikipedia, 2007. Plaza de Arag├│n de Zaragoza, con su colecci├│n de banderas, desaparecida en 2011 por la instalaci├│n en ese mismo entorno de la parada del tranv├¡a.', 2007, 2007, 2007, 'Siglo XXI', 'CENTRO', 41.64798300, -0.88512400, '0101000020E610000056F31C91EF52ECBF97AE601BF1D24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15011380919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15011380919.webp', 'https://www.flickr.com/photos/zaragozaantigua/15011380919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21282, 'Campo Sepulcro 1908', 'Imagen del bastante despejado mar de v├¡as de la estaci├│n de ferrocarril de Campo Sepulcro, o de los Directos, inaugurada en 1896, para la l├¡nea MZA. A la derecha de las v├¡as y andenes, el muro que salvaba el notable desnivel en altura con el inmediato barrio de la Romareda y la estaci├│n de Cari├▒ena, por ello tambi├®n denominado "barrio de Cari├▒ena". Al fondo, parte de los amplios terrenos que la empresa MZA ten├¡a en la zona del antiguo Campo del Sepulcro, desde el Cuartel de Trinitarios y hasta la carretera de Zaragoza a Teruel. A la izquierda, el edificio central de la estaci├│n, tras el que quedaba la semirotonda del dep├│sito de locomotoras, y el acceso principal a la estaci├│n. Bien pronto esta zona, con el impulso ferroviario, ser├¡a uno de los pol├¡gonos industriales destacados de la ciudad. Fuente visual: Museo del ferrocarril.', 1908, 1908, 1908, 'Anos 1900', 'DELICIAS', 41.65208100, -0.89493000, '0101000020E61000006CB2463D44A3ECBFE7ABE46377D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24772714805.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24772714805.webp', 'https://www.flickr.com/photos/zaragozaantigua/24772714805/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21326, 'Campo del Sepulcro 1900', 'Ejercicios militares a caballo del cuerpo de pontoneros en el triangular espacio del Campo del Sepulcro, entre la carretera de Valencia y el paseo de Mar├¡a Agust├¡n, un despejado espacio a poca distancia de los cuarteles de Pontoneros, del Cid y Trinitarios, y junto a los dep├│sitos de agua del Ej├®rcito. Al fondo, el Hospicio Provincial.', 1900, 1900, 1900, 'Anos 1900', 'DELICIAS', 41.65253700, -0.89263900, '0101000020E6100000E84A04AA7F90ECBF0937195586D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49817718368.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49817718368.webp', 'https://www.flickr.com/photos/zaragozaantigua/49817718368/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21476, 'Vista desde Campo Sepulcro 1920', 'Imagen capturada posiblemente desde la casa y f├íbrica de Or├║s, orientada hacia la antigua zona del Campo del Toro, donde el gran edificio de la casa de la Misericordia. Al fondo, el Pilar. A la derecha, la destacada c├║pula de la iglesia parroquial de Santiago el Mayor.', 1920, 1920, 1920, 'Anos 20', 'DELICIAS', 41.65187900, -0.89573700, '0101000020E61000001C261AA4E0A9ECBF7FF964C570D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14777322587.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14777322587.webp', 'https://www.flickr.com/photos/zaragozaantigua/14777322587/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25203, 'Pl. de Basilio Para├¡so 1954', 'AYUNTAMIENTO DE ZARAGOZA/Gerardo Sancho Ramo/1954 (aprox.) Panor├ímica perge├▒ada para la ocasi├│n, en una composici├│n in├®dita, democr├ítica, cient├¡fica y popular, generada en los laboratorios del', 1954, 1954, 1954, 'Anos 50', 'CENTRO', 41.64679700, -0.88655500, '0101000020E6100000745E6397A85EECBF51137D3ECAD24440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14849412191.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14849412191.webp', 'https://www.flickr.com/photos/zaragozaantigua/14849412191/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (21107, 'Puerta del Duque 1889', '"Saragosse. Porte du Duc de la Victoire". Fuente: J. L├®vy et Cie, en "Zaragoza en la mirada ajena", Cortes de Arag├│n, 2012.', 1889, 1889, 1889, 'Siglo XIX', 'CENTRO', 41.64903200, -0.87583800, '0101000020E61000007102D369DD06ECBF5B07077B13D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22536944210.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22536944210.webp', 'https://www.flickr.com/photos/zaragozaantigua/22536944210/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
