INSERT INTO public.photos VALUES (24392, 'San Gil c.1925', 'Imagen capturada durante el proceso de desmontaje de la antigua red a├®rea telef├│nica de la ciudad, y su sustituci├│n por otra nueva, y soterrada. T├®cnicos de la Compa├▒├¡a Telef├│nica Nacional de Espa├▒a posan en el tejado de la iglesia parroquial de San Gil Abad, junto al poste que soportaba el tendido de los hilos telef├│nicos. Al fondo, de derecha a izquierda, la c├║pula de Santa Isabel de Portugal, y las torres de San Felipe y Santiago el Menor, y la de San Pablo Ap├│stol. Fuente visual: www.fundaciontelefonica.com/', 1925, 1925, 1925, 'Anos 20', 'CENTRO', 41.65287200, -0.87950800, '0101000020E6100000744012F6ED24ECBFB03C484F91D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25810412365.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25810412365.webp', 'https://www.flickr.com/photos/zaragozaantigua/25810412365/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
